const snapRaw = $('Get Snapshot').first().json;
const abRaw = $('Get AB Stats').first().json;
const snap = snapRaw.data || snapRaw;
const risk = snap.risk || {};
const funnel = snap.funnel || {};
const pendingPct = ((risk.pendingRatio || 0) * 100).toFixed(1);
const totalLeads = funnel.totalLeads || 0;
const invited = funnel.invited || 0;
const accepted = funnel.accepted || 0;
const replied = funnel.replied || 0;
const acceptanceRate = invited > 0 ? ((accepted / invited) * 100).toFixed(1) : '0.0';
const replyRate = accepted > 0 ? ((replied / accepted) * 100).toFixed(1) : '0.0';
const riskScore = risk.score || 0;
const riskAction = risk.action || 'NORMAL';
const abStats = abRaw.data || abRaw || {};
const abVariants = JSON.stringify(abStats).slice(0, 400);
const weekDate = new Date().toISOString().slice(0, 10);
const prompt = 'Sei un analista LinkedIn automation. Produci un report settimanale in italiano.

DATI SETTIMANA (al ' + weekDate + '):
- Funnel: ' + totalLeads + ' leads totali | ' + invited + ' invitati | ' + accepted + ' accettati | ' + replied + ' risposte
- Acceptance rate: ' + acceptanceRate + '% | Reply rate: ' + replyRate + '%
- Pending ratio: ' + pendingPct + '%
- Risk: ' + riskAction + ' (score ' + riskScore + '/100)
- A/B test variants: ' + abVariants + '

Scrivi un report settimanale in italiano, max 20 righe:

📊 *KPI principali*
[3 bullet con i numeri chiave]

🏆 *Cosa ha funzionato*
[2-3 bullet positivi]

⚠️ *Attenzione su*
[2 bullet critici]

💡 *3 azioni per la prossima settimana*
[3 bullet concreti e misurabili]

Tono: professionale, diretto, numeri precisi.';
const claudeBody = JSON.stringify({ model: 'claude-sonnet-4-6', max_tokens: 600, messages: [{ role: 'user', content: prompt }] });
return [{ json: { claudeBody, weekDate, totalLeads, invited, accepted, replied, acceptanceRate, replyRate, pendingPct, riskScore, riskAction } }];

const response = $input.first().json;
const metrics = $('Prepara Prompt').first().json;
let reportText = 'Report non disponibile — errore generazione Claude.';
try {
  const text = response.content?.[0]?.text || '';
  if (text.length > 10) reportText = text;
} catch(e) {}
return [{ json: { reportText, weekDate: metrics.weekDate } }];
